+import { TProjectPermission } from "@app/lib/types";
+import { ActorAuthMethod, ActorType } from "@app/services/auth/auth-type";
+
+export enum SecretSearchMode {
+  Key = "key",
+  Value = "value",
+  Comment = "comment",
+  All = "all",
+}
+
+export type TSecretSearchDTO = {
+  projectId: string;
+  query: string;
+  mode: SecretSearchMode;
+  environments?: string[];
+  secretPath: string;
+  includeImports: boolean;
+  viewSecretValue: boolean;
+  limit: number;
+  actor: ActorType;
+  actorId: string;
+  actorOrgId: string;
+  actorAuthMethod: ActorAuthMethod;
+};
+
+export type TSecretSearchRow = {
+  secretId: string;
+  folderId: string;
+  projectId: string;
+  environment: string;
+  secretPath: string;
+  secretKeyCiphertext: string;
+  secretKeyIV: string;
+  secretKeyTag: string;
+  secretValueCiphertext: string;
+  secretValueIV: string;
+  secretValueTag: string;
+  secretCommentCiphertext?: string | null;
+  secretCommentIV?: string | null;
+  secretCommentTag?: string | null;
+};
+
+export type TSecretSearchMatch = {
+  secretId: string;
+  secretKey: string;
+  secretValue?: string;
+  secretComment?: string;
+  environment: string;
+  secretPath: string;
+  score: number;
+};
+
+export type TSecretSearchPermission = Pick<
+  TProjectPermission,
+  "actor" | "actorId" | "actorOrgId" | "actorAuthMethod" | "projectId"
+>;
